+fn delete_advantage_ratio(keep_loss: f64, delete_loss: f64) -> f64 {
+    let safe_keep = keep_loss.max(0.0);
+    let safe_delete = delete_loss.max(0.0);
+    if safe_delete <= f64::EPSILON {
+        f64::INFINITY
+    } else {
+        safe_keep / safe_delete
+    }
+}
