+fn min_delete_advantage(calibration: f64, uncertainty: f64) -> f64 {
+    let calibration_penalty = 1.0 - calibration.clamp(0.0, 1.0);
+    uncertainty
+        .mul_add(1.6, calibration_penalty.mul_add(0.9, 1.2))
+        .clamp(1.2, 4.0)
+}
